insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-hearing-aid', '千代田区 高齢者補聴器購入費の助成', '千代田区では、聴覚障害による身体障害者手帳の対象とならない難聴の方の補聴器購入費を一部助成する区独自の制度が案内されています。主たる制度は60歳以上向けの「高齢者補聴器購入費の助成」で、別に60歳未満の難聴者向けの「補聴器購入費の助成」もあり、年齢に応じて窓口・内容・上限額が分かれます。対象や金額の詳細は公式ページで確認してください。', '千代田区に住んでいて耳が聞こえにくく、補聴器を買いたい方向けの区の助成制度です。60歳以上の方が対象の制度がこのページの中心ですが、60歳未満の方向けの別の助成もあり、案内ページや窓口が分かれています。手帳がなくても、医師の診断など条件を満たせば購入費の一部が助成される可能性があります。買う前の申請が必要なため、まず区の窓口に相談してください。', 'subsidy', '千代田区に住所があり、医師の診断などの条件を満たす難聴の方が対象となる可能性があります。このページの中心となる高齢者向け制度は、60歳以上で中等度難聴と医師の診断を受け、聴覚障害による身体障害者手帳を持たず、過去にこの助成を受けていない方が対象とされています。60歳未満の方は別制度（障害者福祉課の補聴器購入費助成）の対象となる可能性があります。いずれも詳細な条件は公式で確認が必要です。', '公式情報によると、助成額には上限が設けられています。60歳以上向けの「高齢者補聴器購入費の助成」は住民税課税世帯で上限72,450円、非課税世帯で上限144,900円とされています。別制度の60歳未満の難聴者向けは、18歳以上は購入費の9割・18歳未満は全額で上限50,000円とされています。金額・区分は変更される場合があるため、必ず最新の公式ページで確認してください。', '高齢者向け制度では、交付決定日から6か月以内に請求が必要と案内されています。申請受付の終期は公式ページに明記がないため、期限は制度・年度により異なる可能性があり、公式ページで確認してください。', '原則として補聴器を購入する前の申請が必要です。医師の意見（申請書の医師意見欄）、補聴器の見積書、世帯の住民税が分かる資料などをそろえ、申請書を区の担当窓口へ提出します。高齢者向け制度は郵送のほかオンライン申請も可能と案内されています。詳細・様式は公式ページで確認してください。', '公式情報によると、申請書（医師意見欄を含む）、補聴器の見積書、世帯全員の住民税が分かる資料（条件により不要な場合あり）などが必要とされています。制度により異なるため、詳細は公式ページで確認してください。', TRUE, '千代田区 保健福祉部 在宅支援課 在宅支援係（高齢者向け）／ 障害者福祉課 障害者福祉係（60歳未満向け）', '03-6265-6482（高齢者向け在宅支援課）／ 03-5211-4214（障害者福祉課）', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/hochoki-konyuhi.html', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/hochoki-konyuhi.html', '高齢者補聴器購入費の助成 - 千代田区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'categorySlugs']::text[], '本ページは公式情報をもとにした概要です。対象・金額・所得区分・年齢区分・申請期限などの詳細や最新情報は、必ず千代田区の公式ページおよび担当窓口でご確認ください。なお千代田区には高齢者向けと60歳未満向けの別制度があり、窓口・上限額が異なります。', 'review', NULL, now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
