insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-chiyoda-hearing-aid","status":"review","title":"千代田区 高齢者補聴器購入費の助成","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/hochoki-konyuhi.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-chiyoda-hearing-aid:dG9reW8tY2hpeW9kYS1oZWFyaW5nLWFpZHzljYPk' from public.support_programs sp where sp.slug='tokyo-chiyoda-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-hearing-aid', '中央区 高齢者補聴器購入費用助成', '中央区にお住まいの65歳以上の方で、耳鼻咽喉科医師が補聴器の使用を必要と認めた場合に、補聴器の購入費用の一部が助成される可能性がある区独自の制度です。聴覚障害の身体障害者手帳をお持ちの方は対象外とされています。助成額や対象の詳細は中央区公式サイトでご確認ください。', '耳が聞こえにくくなった65歳以上の中央区民の方が補聴器を買うとき、費用の一部を区が助成してくれる場合がある制度です。お医者さんに「補聴器が必要」と認めてもらう必要があります。買う前の申請が必要なので、まず区の窓口に相談しましょう。', 'subsidy', '中央区内に住む65歳以上で、耳鼻咽喉科医師が補聴器の使用を必要と認め、過去5年間にこの助成を受けていない方が対象となる可能性があります。聴覚障害による身体障害者手帳をお持ちの方は対象外とされています。対象要件の詳細は公式でご確認ください。', '住民税非課税の方は上限72,000円、住民税課税の方は上限35,000円とされています（令和7年8月1日改定）。金額・上限は変更される可能性があるため、最新の助成額は中央区公式でご確認ください。', '公式ページに明確な申請期限の記載は確認できませんでした。詳細は中央区にお問い合わせください。', '区役所4階の高齢者福祉課窓口または郵送で申請するとされています。補聴器を購入する前に申請し、助成決定の通知を受けてから購入する必要があるとされています。医師の意見書や販売店が作成した見積書などの添付が求められます。手続きの詳細は公式でご確認ください。', '申請書のほか、耳鼻咽喉科医師の意見書、補聴器販売店が作成した見積書などが必要とされています。必要書類の詳細は中央区公式でご確認ください。', FALSE, '中央区 福祉保健部 高齢者福祉課 高齢者活動支援係', '03-3546-5334', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/sonota/hotyoki.html', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/sonota/hotyoki.html', '補聴器購入費用助成 - 中央区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は中央区公式サイトの掲載内容に基づく概要であり、対象要件・助成額・申請方法は改定される場合があります。申請の可否や受給は審査により決定されます。必ず中央区公式サイトまたは担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
