insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-chuo-hearing-aid","status":"published","title":"中央区 高齢者補聴器購入費用助成","officialUrl":"https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/sonota/hotyoki.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-chuo-hearing-aid:dG9reW8tY2h1by1oZWFyaW5nLWFpZHzkuK3lpK7l' from public.support_programs sp where sp.slug='tokyo-chuo-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-hearing-aid', '高齢者補聴器購入費助成事業（港区）', '港区が、加齢などで聴力が低下し日常生活に支障がある高齢者に対し、補聴器の購入費の一部を助成する区独自の制度です。補聴器相談医の受診・診断を経て、認定補聴器技能者が在籍する販売店で相談・購入する流れが前提となっており、購入前の手続きが必要です。対象や助成額・所得要件などの詳細は港区公式サイトでご確認ください。', '港区にお住まいで耳の聞こえに不安のある高齢の方が、補聴器を買うときの費用の一部を区から助成してもらえる制度です。買う前にお医者さん（補聴器相談医）の診察を受け、区の窓口で申し込む必要があります。金額や条件はお住まいの状況によって変わるため、港区の公式ページで確認してください。', 'subsidy', '港区内に居住する高齢者で、聴覚障害による身体障害者手帳の交付を受けていない方などが対象となる可能性があります。年齢要件（おおむね60歳以上）や過去の助成実績の有無などの条件があるため、対象となるかは公式で確認してください。', '購入費の一部を助成。住民税の課税・非課税の別により助成割合や上限額が異なる可能性があります（公式ページでは非課税者は全額・課税者は2分の1とする案内や、上限額の記載があります）。最新の金額・上限は港区公式サイトでご確認ください。', '医師の確認（受診）から一定期間内（公式ページでは6か月以内）に申請書を提出するよう案内されています。期限の詳細は公式でご確認ください。', '購入前に協力医療機関の補聴器相談医を受診し診断（確認書）を受けたうえで、各総合支所の区民課保健福祉係または各高齢者相談センターの窓口で申請書を受け取り申請する流れが案内されています。詳細な手順・受付窓口は港区公式サイトでご確認ください。', '申請書、補聴器相談医による確認書（診断結果）、認定補聴器技能者在籍店の見積書などが必要とされる可能性があります。必要書類は公式サイトでご確認ください。', FALSE, '港区 保健福祉支援部 高齢者支援課 在宅支援係', '03-3578-2400', 'https://www.city.minato.tokyo.jp/zaitakushien/koureisya/hoctyouki/hotyoukijyosei.html', 'https://www.city.minato.tokyo.jp/zaitakushien/koureisya/hoctyouki/hotyoukijyosei.html', '港区ホームページ／高齢者補聴器購入費助成事業', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '助成額・上限・所得要件などは改定される場合があります。最新かつ正確な情報は必ず港区公式サイトまたは担当窓口でご確認ください。本ページは制度の概要を分かりやすく案内するもので、受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
