insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-minato-hearing-aid","status":"published","title":"高齢者補聴器購入費助成事業（港区）","officialUrl":"https://www.city.minato.tokyo.jp/zaitakushien/koureisya/hoctyouki/hotyoukijyosei.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-minato-hearing-aid:dG9reW8tbWluYXRvLWhlYXJpbmctYWlkfOmrmOm9' from public.support_programs sp where sp.slug='tokyo-minato-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-hearing-aid', '新宿区 高齢者の補聴器の支給・購入費助成', '新宿区が、65歳以上で聴力が低下した区民（障害者制度で補聴器の支給を受けていない方）を対象に、補聴器の現物支給または購入費の一部助成（公式で72,450円を上限に実費を助成と案内）を行う区独自制度です。住民税非課税世帯・生活保護受給者は受給者負担が生じないと案内されています。対象・金額・条件は変更される場合があるため、必ず新宿区公式ページと窓口でご確認ください。', '新宿区にお住まいの65歳以上で耳が聞こえにくくなった方に向けて、新宿区が補聴器そのものの支給や、補聴器を買うときの費用の一部を助成する制度です。受けられるかどうかや金額は人によって異なるため、まずは新宿区の窓口（高齢者支援課）に相談してみてください。', 'subsidy', '新宿区にお住まいで、65歳以上で聴力が低下した方のうち、障害者の制度で補聴器を支給されていない方が対象となる可能性があります。具体的な年齢・聴力・所得などの要件は公式ページおよび窓口でご確認ください。', '公式案内では、補聴器の現物支給（利用者負担：片耳2,000円・両耳4,000円、住民税非課税世帯・生活保護受給者は負担なし）と、補聴器購入費の一部助成（72,450円を上限に実費を助成）の2通りが示されています。金額・上限は変更される場合があるため公式で確認してください。', '公式ページに明確な申請期限の記載は確認できませんでした。詳細は窓口でご確認ください。', '公式案内によると、耳鼻科を受診して所定の受診結果報告書・聴力検査結果などを準備したうえで、高齢者支援課（区役所本庁舎2階）または各高齢者総合相談センターの窓口で申請する流れとされています。申請前の購入は助成対象外となる場合があるため、購入前に新宿区公式ページと窓口で手順・必要書類をご確認ください。', '公式案内では、申請書・受診結果報告書・聴力検査結果表などが挙げられています。最新の必要書類は新宿区公式ページおよび窓口でご確認ください。', FALSE, '新宿区 福祉部 高齢者支援課 高齢者支援係', '03-5273-4305', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00009.html', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00009.html', '補聴器の支給等 - 新宿区', '2026-06-24', 'high', ARRAY['targetPeople（所得制限・聴力要件・医師意見の細目）', 'benefitAmountText（令和8年4月改定後の上限額・負担額の細目）', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは新宿区公式サイトの情報をもとにした概要です。対象・金額・申請方法は変更される場合があります。最新かつ正確な情報は新宿区公式ページおよび窓口でご確認ください。受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
