insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-shinjuku-hearing-aid","status":"published","title":"新宿区 高齢者の補聴器の支給・購入費助成","officialUrl":"https://www.city.shinjuku.lg.jp/fukushi/file05_02_00009.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-shinjuku-hearing-aid:dG9reW8tc2hpbmp1a3UtaGVhcmluZy1haWR85paw' from public.support_programs sp where sp.slug='tokyo-shinjuku-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-hearing-aid', '高齢者補聴器購入費用助成事業（文京区）', '文京区が、区内在住で一定の年齢・難聴の要件に該当する高齢者を対象に、補聴器本体の購入費の一部を助成する区独自の制度です。医師の診断で補聴器が必要と認められることなどが要件で、購入前の申請・助成決定が必要です。対象や上限額の詳細は公式ページでご確認ください。', '文京区では、耳の聞こえに不安のある高齢の方が補聴器を買うときに、購入費の一部を区が助成する制度があります。お医者さん（耳鼻咽喉科）の診断を受け、必要と認められたうえで、買う前に区へ申請して助成が決まることが必要です。対象になるかどうかや金額は、区の公式ページで確認してください。', 'subsidy', '文京区内在住で、申請年度に65歳以上となる方のうち、医師の診断で補聴器が必要と認められた方などが対象となる可能性があります。聴覚障害による障害者手帳をお持ちの方は原則対象外ですが、所得（納税額）の制限で補装具費の支給を受けられない場合などは対象となることがあります。要件の詳細は公式ページでご確認ください。', '補聴器本体の購入費に対し、片耳・両耳を問わず72,450円を上限として助成（令和7年4月1日から）。金額は年度や制度改定により変わる場合があります。', '医師の意見書記載日から6か月以内に高齢福祉課へ提出し、助成決定通知から6か月以内に購入するなどの期限があります。詳細・最新の取扱いは公式ページでご確認ください。', '耳鼻咽喉科で申請書兼意見書による診断を受け、補聴器が必要と認められた後、申請書兼意見書などの書類を文京区高齢福祉課の窓口へ提出または郵送して申請します。購入前の申請・助成決定が必要です。', '申請書兼意見書（医師の意見書記載日から6か月以内に提出）、領収書、通帳のコピー、請求書兼口座振替依頼書など。必要書類の詳細は公式ページでご確認ください。', FALSE, '文京区 福祉部 高齢福祉課 高齢福祉推進係', '03-5803-1213', 'https://www.city.bunkyo.lg.jp/b017/p003186.html', 'https://www.city.bunkyo.lg.jp/b017/p003186.html', '高齢者補聴器購入費用助成事業 | 文京区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本内容は文京区公式ページを参照した概要です。対象要件・助成額・所得要件・申請期限などは年度や個別の状況により異なる場合があるため、申請の前に必ず公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
