insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-bunkyo-hearing-aid","status":"published","title":"高齢者補聴器購入費用助成事業（文京区）","officialUrl":"https://www.city.bunkyo.lg.jp/b017/p003186.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-bunkyo-hearing-aid:dG9reW8tYnVua3lvLWhlYXJpbmctYWlkfOmrmOm9' from public.support_programs sp where sp.slug='tokyo-bunkyo-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-hearing-aid', '台東区 聞こえの改善機器購入費助成（高齢者向け補聴器購入費助成）', '台東区が実施する高齢者向けの補聴器（聞こえの改善機器）購入費助成制度。65歳以上で耳鼻咽喉科医により補聴器の装用が必要と認められ、聴覚障害の身体障害者手帳を持たない区民が対象となる可能性があります。補聴器本体の購入費（1人1回限り）の一部を助成。詳細・最新の条件は台東区公式ページでご確認ください。', '耳が聞こえにくくなった台東区の65歳以上の方が、補聴器を買うときの費用の一部を区が助成してくれる制度です。お医者さん（耳鼻咽喉科）に補聴器が必要と認められることなどが条件です。詳しくは区の窓口や公式ページで確認しましょう。', 'subsidy', '台東区に住所がある65歳以上で、耳鼻咽喉科医により補聴器の装用が必要と認められ、聴覚障害による身体障害者手帳を持たず、過去にこの助成を受けていない方が対象となる可能性があります。該当の可否は公式でご確認ください。', '公式によると、補聴器本体の購入費（1人1回限り）について、住民税非課税・生活保護受給中の方は上限144,900円、住民税課税の方は上限72,450円が助成の目安とされています（購入額が上限未満の場合は購入額が助成額）。金額・区分は変更される場合があるため、最新額は公式でご確認ください。', '公式によると、医師意見書は医師記入日から3か月以内の提出、請求は申請日の翌年度末までが期限の目安とされています。最新の取扱いは公式でご確認ください。', '台東区役所2階5番の高齢福祉課窓口で、本人確認書類・医師意見書・領収書（写し）等を提出して申請する方法が公式で案内されています。本人が申請できない場合は代理申請が可能とされています。詳細な手順は公式ページでご確認ください。', '公式案内では、本人確認書類、医師意見書、領収書（写し）、補聴器の特定ができる書類（写し）、請求書兼口座振替依頼書などが挙げられています。', FALSE, '台東区 高齢福祉課 総合相談・給付担当', '03-5246-1227', NULL, 'https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/kikoe.html', '聞こえの改善機器購入費助成 - 台東区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '助成額・対象・所得区分・申請手続きは変更される場合があります。実際の申請可否や金額は必ず台東区の公式ページ・窓口でご確認ください。本サイトの情報は受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
