insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-taito-hearing-aid","status":"published","title":"台東区 聞こえの改善機器購入費助成（高齢者向け補聴器購入費助成）","officialUrl":"https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/kikoe.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-taito-hearing-aid:dG9reW8tdGFpdG8taGVhcmluZy1haWR85Y+w5p2x' from public.support_programs sp where sp.slug='tokyo-taito-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-hearing-aid', '墨田区 高齢者補聴器購入費助成', '墨田区では、聴力の低下により日常生活でのコミュニケーションが取りにくくなった高齢者を対象に、補聴器の購入費用の一部を助成する区独自の制度を設けています。区内在住の満65歳以上で、身体障害者手帳の対象外であり、耳鼻咽喉科医師により所定の聴力基準を満たすと認められた方が対象となる可能性があります。助成上限額は住民税の課税状況によって異なり、公式ページによると令和8年(2026年)4月1日以降の申請分から上限額が拡充されています。金額・所得区分・聴力基準などの詳細は変更される場合があるため、申請前に必ず墨田区の公式ページおよび高齢者福祉課支援係でご確認ください。', '耳が聞こえにくくなった65歳以上の墨田区民が補聴器を買うとき、区がその費用の一部を助成してくれる制度です。住民税が非課税か課税かで助成の上限額が変わります。まず申請書をもらい、耳鼻咽喉科で聴力を調べて医師に書類を書いてもらってから区に提出します。対象になるかどうかや金額の詳しい条件は、墨田区の公式ページや高齢者福祉課で確認してください。', 'subsidy', '墨田区内在住の満65歳以上で、身体障害者手帳の対象外であり、耳鼻咽喉科の医師により所定の聴力基準(中等度難聴以上など)を満たすと認められた方が対象となる可能性があります。対象要件・聴力基準の詳細は公式でご確認ください。', '助成上限額は住民税の課税状況により異なります。公式ページによると、令和8年(2026年)4月1日以降の申請分は住民税非課税者で上限72,450円、住民税課税者で上限40,000円とされています(実際の購入額が上限に満たない場合は購入額が助成額)。金額は改定される場合があるため、最新の金額・適用条件は墨田区公式ページでご確認ください。', '公式案内によると、申請書の提出期限は医師意見欄の記入日から3か月以内とされています。詳細は公式でご確認ください。', '申請書を入手のうえ耳鼻咽喉科を受診し、医師の証明・意見欄の記入とオージオグラム(純音聴力検査表)を添えて、墨田区(高齢者福祉課支援係)の窓口へ提出する流れが案内されています。詳しい申請方法・受付窓口は公式ページでご確認ください。', '申請書、耳鼻咽喉科医師による証明・意見書、オージオグラム(純音聴力検査表)などが案内されています。必要書類の詳細は公式ページでご確認ください。', FALSE, '墨田区 高齢者福祉課 支援係', '03-5608-6168', NULL, 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/ziritu_sien/ta90200020150714170.html', '高齢者の補聴器購入費を助成しています（墨田区公式ホームページ）', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople(聴力基準・対象要件の詳細)']::text[], '本ページは墨田区公式情報をもとにした概要です。対象要件・助成金額・聴力基準・申請方法などは変更される場合があります。最新かつ正確な内容は必ず墨田区の公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
