insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-sumida-hearing-aid","status":"published","title":"墨田区 高齢者補聴器購入費助成","officialUrl":"https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/ziritu_sien/ta90200020150714170.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-sumida-hearing-aid:dG9reW8tc3VtaWRhLWhlYXJpbmctYWlkfOWiqOeU' from public.support_programs sp where sp.slug='tokyo-sumida-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-hearing-aid', '高齢者補聴器の現物支給及び購入費助成（江東区）', '江東区では、加齢性難聴のある高齢者の社会参加や介護予防を支えるため、耳鼻咽喉科の聴力検査で必要と認められた方に、区指定の補聴器の現物支給または購入費の助成（いずれか一方）を行う区独自制度を案内しています。対象や金額は公式ページでの確認が必要です。', '江東区に住む65歳以上の方で、耳鼻科の検査で補聴器が必要と認められた場合、区から補聴器そのものを受け取るか、購入費の助成（上限あり）のどちらかを受けられる可能性がある区の制度です。詳しい対象や金額は区の公式ページでご確認ください。', 'subsidy', '江東区内在住の65歳以上で、耳鼻咽喉科の聴力検査により補聴器が必要と認められた方が対象となる可能性があります。障害者総合支援法による補聴器の支給を受けていないことなどの条件があるため、対象に該当するかは公式ページでご確認ください。', '現物支給（区指定の補聴器）または購入費助成のいずれか一方。購入費助成の上限額は公式ページ記載で72,450円（購入金額がこれ未満の場合は実費分）とされていますが、金額は変更される場合があるため公式での確認が必要です。', '公式ページで確認が必要です。', '耳鼻咽喉科で聴力検査を受け、医師の証明とオージオグラム等を添付した申請書を窓口へ提出します（郵送による申請も可能）。窓口は区役所3階の介護保険課在宅支援係または長寿サポートセンターです。詳細・最新の手続きは公式ページでご確認ください。', '申請書、耳鼻咽喉科医師の証明、聴力検査結果（オージオグラム）等。詳細は公式ページでご確認ください。', FALSE, '江東区 福祉部介護保険課 在宅支援係', '03-3647-4319', 'https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6597.html', 'https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6597.html', '高齢者補聴器の現物支給及び購入費助成｜江東区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは公的支援制度の概要を分かりやすく紹介するものです。対象・金額・申請方法などの最終的な内容や最新情報は、必ず江東区の公式ページでご確認ください。制度内容は変更される場合があります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
