insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-koto-hearing-aid","status":"published","title":"高齢者補聴器の現物支給及び購入費助成（江東区）","officialUrl":"https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6597.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-koto-hearing-aid:dG9reW8ta290by1oZWFyaW5nLWFpZHzpq5jpvaLo' from public.support_programs sp where sp.slug='tokyo-koto-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-hearing-aid', '品川区 高齢者補聴器購入費助成事業', '品川区では、加齢などで聞こえにくくなった高齢者の補聴器購入費を助成する区独自の制度「高齢者補聴器購入費助成事業」を実施しています。区内に住所がある満65歳以上で、聴覚障害による補装具の支給を受けられない方のうち、耳鼻咽喉科医が所定の聴力基準（両耳おおむね40デシベル以上70デシベル未満の中等度難聴など）を満たし補聴器の装用が必要と認めた方が対象となる可能性があります。助成は72,450円を上限とし、購入費がこれに満たない場合は実費が案内されています。なお、65歳未満の方については別の制度が用意されている場合があるため、詳しくは品川区の公式ページおよび担当課でご確認ください。対象条件・金額などは年度や個別状況で変わることがあります。', '品川区には、65歳以上の方が補聴器を買うときに、その費用の一部（72,450円まで）を区が助けてくれる制度があります。耳鼻咽喉科のお医者さんに「補聴器が必要」と認めてもらうことなどが条件です。区役所の高齢者地域支援課の窓口か郵送で申し込めます。65歳より下の方には別の制度がある場合もあります。金額や条件は年度などで変わることがあるので、申し込む前に品川区のホームページや窓口で確認してください。', 'subsidy', '品川区内に住所がある満65歳以上の方で、聴覚障害による補装具の支給を受けられない方が対象とされています。あわせて、耳鼻咽喉科医が所定の聴力基準（両耳おおむね40デシベル以上70デシベル未満の中等度難聴など）を満たし、補聴器の装用が必要と認めた方が想定されています。該当するかどうかは品川区の公式ページおよび担当課でご確認ください。', '補聴器購入費のうち72,450円を上限とする助成が案内されています（購入費がこれに満たない場合は実際の購入費）。金額は年度や制度改定で変わる可能性があるため、最新額は品川区の公式ページでご確認ください。', '公式ページに明確な申請期限の記載は確認できませんでした。実施状況・受付期間は品川区の公式ページでご確認ください。', '耳鼻咽喉科を受診のうえ、医師の意見と聴力図（オージオグラム）を添えて申請書を提出します。受付は品川区役所（福祉部 高齢者地域支援課・本庁舎3階）の窓口または郵送とされています。申請の前に必ず公式ページ・担当課で最新の手続きをご確認ください。', '申請書のほか、耳鼻咽喉科医による意見および聴力図（オージオグラム）などが必要とされています。詳細な必要書類は品川区の公式ページ・担当課でご確認ください。', FALSE, '品川区 福祉部 高齢者地域支援課', '03-5742-6733', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/20230428084925.html', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/20230428084925.html', '高齢者補聴器購入費助成事業｜品川区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本ページは品川区公式情報をもとにした概要です。対象条件・助成金額・必要書類・受付状況は変更される場合があります。最新かつ正確な内容は必ず品川区の公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
