insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-shinagawa-hearing-aid","status":"published","title":"品川区 高齢者補聴器購入費助成事業","officialUrl":"https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/20230428084925.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-shinagawa-hearing-aid:dG9reW8tc2hpbmFnYXdhLWhlYXJpbmctYWlkfOWT' from public.support_programs sp where sp.slug='tokyo-shinagawa-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-hearing-aid', '高齢者補聴器購入費助成事業（目黒区）', '目黒区が実施する、満65歳以上で住民税非課税の区民を対象とした補聴器購入費の助成制度。聴覚障害による補装具費支給の対象とならない方が対象で、耳鼻咽喉科専門医の証明等が必要。助成上限は公式ページによると令和8年4月1日申請分から70,000円で、本体費用・1人1回限り。対象・金額・要件の詳細は必ず目黒区公式でご確認ください。', '目黒区では、65歳以上で住民税が非課税の方が補聴器を買うとき、その費用の一部（上限あり）を区が助成する制度があります。耳の聞こえについて医師の証明などが必要で、申請は補聴器を買う前に高齢福祉課で行います。対象になるかどうかや金額は、区の公式ページで確認してください。', 'subsidy', '目黒区内在住で満65歳以上、住民税非課税の方のうち、聴覚障害による補装具費の支給対象とならず、耳鼻咽喉科専門医に補聴器装用の必要性等を認められた方が対象となる可能性があります（両耳の聴力レベルがおおむね40デシベル以上70デシベル未満等の基準。詳しい要件は目黒区公式でご確認ください）。', '助成上限額は、目黒区公式ページによると令和8年（2026年）4月1日申請分から70,000円。購入金額が上限額に満たない場合は実際の購入金額（千円未満切捨て）が助成額となります。対象は補聴器本体費用で、1人1回限り。最新の金額は公式でご確認ください。', '申請期限・受付期間は目黒区公式ページでご確認ください。補聴器購入後の事後申請ではなく、事前確認・事前申請が必要とされるため、購入前に窓口へご相談ください。', '高齢福祉課在宅事業係の窓口で手続きします。一般的な流れは、(1)事前確認依頼書の提出、(2)耳鼻咽喉科の受診・医師の証明、(3)認定補聴器専門店での見積取得、(4)申請書類の提出、(5)補聴器の購入、(6)費用の請求、です。詳細・最新の手順は目黒区公式ページでご確認ください。', '申請時は助成申請書、医師意見書（聴力図添付）、認定補聴器専門店の見積書等、請求時は購入実績報告書兼請求書、領収書（原本）、納品書等が必要となる可能性があります。必要書類の詳細は目黒区公式でご確認ください。', FALSE, '目黒区 健康福祉部 高齢福祉課 在宅事業係', '03-5722-9839', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/hochouki.html', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/hochouki.html', '高齢者補聴器購入費助成事業 | 目黒区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本ページは目黒区公式情報をもとにした概要です。対象要件・助成額・申請方法は変更される場合があるため、申請前に必ず目黒区公式ページおよび高齢福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
