insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-meguro-hearing-aid","status":"published","title":"高齢者補聴器購入費助成事業（目黒区）","officialUrl":"https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/hochouki.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-meguro-hearing-aid:dG9reW8tbWVndXJvLWhlYXJpbmctYWlkfOmrmOm9' from public.support_programs sp where sp.slug='tokyo-meguro-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-hearing-aid', '大田区 高齢者補聴器購入費助成', '大田区にお住まいの満65歳以上で、耳鼻咽喉科の医師が補聴器の使用を必要と認めた方などを対象に、補聴器の購入費の一部を助成する区独自の制度です。助成額や対象要件は公式ページでご確認ください。', '大田区の65歳以上の方で、お医者さん（耳鼻咽喉科）が補聴器が必要と認めた場合に、補聴器の購入費の一部を区が助成してくれる制度です。お住まいの地域の窓口にご相談ください。', 'subsidy', '大田区内に住所を有し現に居住する満65歳以上の方で、聴覚障害による身体障害者手帳を所持しておらず、耳鼻咽喉科の医師が補聴器の使用を必要と認め、過去5年以内に同助成を受けていない方が対象となる可能性があります。なお、令和8年4月1日の改正で住民税課税世帯も助成対象に拡充されています。詳しい対象要件は公式ページでご確認ください。', '公式案内では、一人1回につき50,000円を限度に助成され、助成は一人あたり5年間に1回とされています。金額・回数は年度や制度改正で変わる場合があるため、最新の内容は公式ページでご確認ください。', '申請期限・受付期間については公式ページでご確認ください。', '原則として、購入前にお住まいを管轄する地域包括支援センター（高齢者の相談窓口）または各地域福祉課の高齢者地域支援担当の窓口へ申し込みます。耳鼻咽喉科の医師の意見と申請書の提出が必要とされています。詳細・最新の手続きは公式ページでご確認ください。', '耳鼻咽喉科の医師の意見（意見書等）および購入前の申請書の提出が必要とされています。必要書類の詳細は公式ページでご確認ください。', FALSE, '大田区 各地域福祉課 高齢者地域支援担当／お住まいを管轄する地域包括支援センター', '03-5764-0658', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/hocyouki.html', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/hocyouki.html', '大田区ホームページ：高齢者補聴器購入費助成', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', '聴力レベル(dB)の基準', '所得・住民税要件', 'requiredDocumentsText']::text[], '本内容は公式ページをもとに作成した参考情報です。対象要件・助成額・申請方法は変更される場合があるため、申請前に必ず大田区の公式ページおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
