insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-ota-hearing-aid","status":"published","title":"大田区 高齢者補聴器購入費助成","officialUrl":"https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/hocyouki.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-ota-hearing-aid:dG9reW8tb3RhLWhlYXJpbmctYWlkfOWkp+eUsOWM' from public.support_programs sp where sp.slug='tokyo-ota-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'setagaya'), 'tokyo-setagaya-hearing-aid', '補聴器購入費助成（世田谷区）', '世田谷区が独自に実施する補聴器購入費の助成制度です。聞こえに支障のある区民を対象に、補聴器の購入費の一部を助成します。年齢区分（65歳以上の高齢者向け、18歳から64歳の中等度難聴者向け、18歳未満の児童向け）ごとに、対象者の要件・助成上限額・申請先の窓口が分かれています。住民税の課税状況や聴力レベルなどの要件があり、対象となるかどうかや助成額は公式ページで確認してください。', '世田谷区では、耳が聞こえにくい区民の方が補聴器を買うときに、その費用の一部を区が助成する制度があります。65歳以上の方向け、18歳から64歳の方向け、18歳未満の子ども向けと、年齢によって対象や助成額、相談する窓口が分かれています。住民税が非課税であることや、医師の診察で一定の聴力と認められることなどの条件があります。自分が対象になるか、いくら助成されるかは、区の公式ページで確認してください。', 'subsidy', '世田谷区に住所のある区民で、聞こえ（聴力）に支障があり補聴器が必要と認められる方が対象となる可能性があります。区の制度は年齢区分（65歳以上／18歳から64歳／18歳未満）ごとに要件が分かれ、住民税非課税であること、医師の診察で一定以上の聴力レベルと認められること、身体障害者手帳の対象外であること、一定期間内に同様の助成を受けていないことなどの条件が設けられている場合があります。ご自身が対象となるか、詳しい要件は世田谷区の公式ページで確認してください。', '助成の上限額は年齢区分により異なります。公式ページでは、65歳以上向けは50,000円以内、18歳から64歳の中等度難聴者向けは上限50,000円（両耳の場合100,000円）、18歳未満（学生・児童）向けは基準額137,000円を上限に購入費の一部、といった内容が案内されています。実際の助成額・上限・助成割合は申請時点の制度内容により変わる可能性があるため、公式ページで確認してください。', '高齢者向けの案内では、医師意見欄の作成日からおおむね6か月以内に申請し、助成決定からおおむね1年以内に購入する、といった期限が示されています。期限は制度・年齢区分により異なる可能性があるため、公式ページで確認してください。', '認定補聴器技能者が在籍する販売店等で相談し見積書を取得のうえ、医師の意見記入を受けた申請書とあわせて、郵送または電子申請（LoGoフォーム）で世田谷区の担当課へ提出する流れが案内されています。事前に担当課へ電話して申請書を入手する必要がある場合があります。具体的な手続きは公式ページで確認してください。', '記入済みの申請書（医師の意見記入を含む）、販売店が作成した見積書などが必要と案内されています。必要書類は年齢区分・申請方法により異なる場合があるため、公式ページで確認してください。', TRUE, '世田谷区 高齢福祉部 高齢福祉課（65歳以上向け）／障害福祉部 障害施策推進課（18歳から64歳向け）', '03-5432-2256', 'https://www.city.setagaya.lg.jp/02082/10803.html', 'https://www.city.setagaya.lg.jp/02082/10803.html', '高齢者（65歳以上）のための補聴器購入費助成 - 世田谷区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本ページは世田谷区公式の案内をもとにした概要です。対象要件・助成額・申請期限・申請方法は年齢区分や申請時点の制度内容により異なる場合があります。最新かつ正確な情報は必ず世田谷区の公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
