insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-setagaya-hearing-aid","status":"published","title":"補聴器購入費助成（世田谷区）","officialUrl":"https://www.city.setagaya.lg.jp/02082/10803.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-setagaya-hearing-aid:dG9reW8tc2V0YWdheWEtaGVhcmluZy1haWR86KOc' from public.support_programs sp where sp.slug='tokyo-setagaya-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-hearing-aid', '渋谷区 高齢者補聴器購入費助成', '渋谷区が実施する、加齢に伴う難聴で身体障害者手帳の対象とならない高齢者向けに、補聴器の購入費用の一部を助成する区独自制度です。対象や金額は所得など一定の要件を満たすかどうかで変わるため、必ず渋谷区公式ページで最新の条件をご確認ください。', '耳が聞こえにくくなった65歳以上の渋谷区民で、身体障害者手帳の対象にならない方に向けて、補聴器の購入費の一部を助成する制度です。所得などの条件があり、すべての方が対象になるとは限りません。詳しくは区の公式ページや高齢者福祉課でご確認ください。', 'subsidy', '渋谷区に住民登録があり在住する65歳以上で、住民税非課税または合計所得金額135万円以下の方のうち、耳鼻咽喉科専門医から本事業の基準を満たす証明を受け、聴覚障害による身体障害者手帳の対象とならない方が対象となる可能性があります。5年以内に同事業の助成を受けている場合は対象外となるなど条件があり、該当の可否は公式で確認が必要です。', '助成上限額は補聴器1台分の本体費用の一部で、申請書兼医師意見書の提出時期によって異なるとされています。公式案内では、令和8年4月30日までの提出は上限45,000円、令和8年5月1日以降の提出は上限72,000円とされ、現時点では72,000円が案内されています(購入金額が上限に満たない場合は購入額(千円未満切り捨て)が助成額)。適用される金額は申請時期により変わるため、必ず公式でご確認ください。', '申請書兼医師意見書の医師記入欄に記入を受けた日から3か月以内に提出する必要があるとされています。購入は決定通知書到着後、原則3か月以内とされています。最新の取扱いは公式で確認してください。', '地域包括支援センターまたは渋谷区役所本庁舎5階の高齢者福祉課サービス事業係の窓口で申請書兼医師意見書を受け取り、耳鼻咽喉科を受診して医師の記入を受けたうえで提出します。郵送での提出にも対応しています。詳細な手順・送付先は公式ページでご確認ください。', '申請書兼医師意見書(耳鼻咽喉科医による記入済み)、聴力検査結果(オージオグラム)、領収書(原本)、請求書兼口座振替依頼書、補聴器購入明細書などが必要とされています。詳細は公式ページでご確認ください。', FALSE, '渋谷区 高齢者福祉課 サービス事業係', '03-3463-1873', 'https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/hocyouki-jyosei.html', 'https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/hocyouki-jyosei.html', '高齢者補聴器購入費助成 | 高齢者の在宅支援 | 渋谷区ポータル', '2026-06-24', 'high', ARRAY['benefitAmountText']::text[], '本ページは渋谷区公式情報をもとにした概要案内であり、対象・金額・申請方法等は変更される場合があります。実際の支給可否や金額は審査により決まります。申請前に必ず渋谷区公式ページおよび高齢者福祉課で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
