insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-shibuya-hearing-aid","status":"published","title":"渋谷区 高齢者補聴器購入費助成","officialUrl":"https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/hocyouki-jyosei.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-shibuya-hearing-aid:dG9reW8tc2hpYnV5YS1oZWFyaW5nLWFpZHzmuIvo' from public.support_programs sp where sp.slug='tokyo-shibuya-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-hearing-aid', '中野区高齢者補聴器購入費用助成', '中野区が、聴力が低下した高齢者を対象に、補聴器の購入費用の一部を助成する区独自の制度です。区に申請して交付決定を受けてから購入した補聴器が対象となる可能性があり、詳細・最新の要件は中野区公式ページでで確認ください。', '中野区にお住まいの65歳以上で、中等度の難聴などにより補聴器が必要と認められた方を対象に、補聴器の購入費用の一部を区が助成する制度です。先に区へ申請して交付決定を受けることが必要とされており、対象や金額・所得の条件は公式ページでご確認ください。', 'subsidy', '中野区の住民基本台帳に登録されている65歳以上で、世帯全員の前年の合計所得金額が一定額未満（公式では350万円未満と記載）、かつ中等度難聴（おおむね40〜70デシベル）と診断された方、または耳鼻咽喉科医に補聴器の装用が必要と認められた方が対象となる可能性があります。過去5年以内に同助成を受けていないことなどの条件もあるため、詳細は公式でご確認ください。', '公式によると、補助限度額は片耳の購入で1台につき45,000円、両耳の購入で90,000円とされています（金額は年度により変わる可能性があるため、最新は中野区公式でご確認ください）。', '公式によると、受診日から3か月以内に申請、助成金の請求は交付決定の日から1年以内とされています。最新の期限は公式でご確認ください。', '公式によると、申請は郵送、窓口（区役所・地域包括支援センター）、またはインターネット（電子申請サービス／LoGoフォーム）で行えるとされています。受診日から3か月以内の申請が必要とされ、交付決定前に購入した補聴器は対象外とされています。最新の手続きは公式ページでご確認ください。', '公式によると、申請時は申請書、検査結果が添付された医師意見書、認定補聴器技能者が在籍する店舗が発行した補聴器の見積書、（該当者は）世帯全員の前年中の合計所得金額がわかる資料などが必要とされています。請求時は請求書、アフターフォロー実施確認書、領収書、振込口座がわかる資料などが必要とされています。', TRUE, '中野区 地域支えあい推進部 地域包括ケア推進課 在宅サービス係', '03-3228-5632', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/0235245120240605163422503.html', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/0235245120240605163422503.html', '高齢者の方へ、補聴器購入費用を助成します（注意：購入済の補聴器は対象外です） | 中野区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは中野区公式サイトの情報をもとにした概要です。対象・助成額・所得要件・申請方法は年度や個別の状況により異なる場合があります。実際の申請可否や条件は、必ず中野区公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
