insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-nakano-hearing-aid","status":"published","title":"中野区高齢者補聴器購入費用助成","officialUrl":"https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/0235245120240605163422503.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-nakano-hearing-aid:dG9reW8tbmFrYW5vLWhlYXJpbmctYWlkfOS4remH' from public.support_programs sp where sp.slug='tokyo-nakano-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-hearing-aid', '杉並区 高齢者補聴器購入費助成', '杉並区が、聴力が低下した高齢者の補聴器の適切な装用と日常生活でのより良いコミュニケーションを支援するため、補聴器の購入費用の一部を助成する区独自の制度です。身体障害者手帳の交付対象とならない方が対象となる可能性があり、認知症予防の一助とすることも目的とされています。対象・助成限度額・所得区分などの詳細は公式ページで確認してください。', '耳が聞こえにくくなった高齢の方が補聴器を買うとき、杉並区が費用の一部を助成してくれる制度です。身体障害者手帳の対象にならない方が対象になる場合があります。必ず買う前に申請が必要です。金額や条件は区の公式ページで確認してください。', 'subsidy', '杉並区内に住所を有する満65歳以上で、聴覚障害による身体障害者手帳の交付対象とならず、補聴器相談医から補聴器の必要性を認められた方が対象となる可能性があります。詳しい年齢・在住・所得などの要件は公式ページで確認してください。', '助成限度額は世帯の課税状況により異なり、公式ページでは住民税非課税世帯72,450円・住民税課税世帯36,230円と案内されています（金額は改定される場合があるため、最新額は公式ページでご確認ください）。', '医師意見書の記入を受けた日から6カ月以内に申請書等を提出する必要があると案内されています。', '電子フォーム・郵送・窓口での申請が案内されています。補聴器を購入した後の申請は助成対象外とされており、購入前の申請が必要とされています。医師意見書（オージオグラムを添付）・見積書・申請書などを、医師意見書の記入を受けた日から6カ月以内に提出する流れが案内されています。最新の手続き・必要書類は公式ページや担当窓口でご確認ください。', '医師意見書（オージオグラム添付）、補聴器の見積書、申請書など。詳細・最新の様式は公式ページでご確認ください。', TRUE, '杉並区 保健福祉部 高齢者在宅支援課 管理係', '03-5307-0649', NULL, 'https://www.city.suginami.tokyo.jp/s039/1170.html', '高齢者補聴器購入費助成｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '助成限度額・所得区分・対象などの詳細は改定される場合があります。申請前に必ず杉並区の公式ページまたは担当窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
