insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-hearing-aid', '豊島区 高齢者補聴器購入費助成事業', '豊島区が、聴覚障害による補聴器(補装具)の支給対象とならない高齢者を対象に、耳鼻咽喉科医師から中程度難聴の証明を受けた場合に補聴器の購入費の一部を助成する区独自の制度です。助成上限額は介護保険料の所得段階により異なり、公式での確認が必要です。', '豊島区にお住まいの65歳以上で、耳が聞こえにくく医師から中程度難聴と証明された方に、区が補聴器の購入費の一部を助成する制度です。助成額の上限は所得段階によって変わります。購入する前の申請が必要です。', 'subsidy', '豊島区に住所のある満65歳以上で、聴覚障害による補聴器(補装具購入費)の支給対象とならず、耳鼻咽喉科の医師から中程度難聴の証明を受けた方などが対象となる可能性があります。要件があるため、対象に該当するかは公式ページや高齢者総合相談センターで確認してください。', '助成上限額は介護保険料の所得段階に応じて異なり、段階1〜5は上限50,000円、段階6以上は上限20,000円とされています(購入額が上限を下回る場合は購入額・千円未満切り捨て)。金額や所得段階の詳細は変更される場合があるため、必ず公式ページで確認してください。', '申請期限の明確な記載はありませんが、公式ページには「予算上限に達し次第、当年度分の受付を終了します」と記載されています。購入前の事前申請が必要なため、補聴器の購入を検討する前に早めに高齢者総合相談センターへ相談・申請してください。最新の受付状況は公式ページで確認してください。', '地域の高齢者総合相談センターへ申請書類を提出する方法のほか、インターネット電子申請サービスでの申請も案内されています。購入前の事前申請が必要で、区から決定通知書が届いた後に補聴器を購入し、助成金を請求する流れです。詳しい手順は公式ページで確認してください。', '耳鼻咽喉科の医師が作成した証明書(区様式・おおむね3か月以内のもの)、高齢者補聴器購入費助成申請書などが必要とされています。最新の必要書類は公式ページや窓口で確認してください。', TRUE, '豊島区 高齢者福祉課 高齢者事業グループ', '03-4566-2432', NULL, 'https://www.city.toshima.lg.jp/379/koureisyazigyo/1805080937.html', '高齢者補聴器購入費助成事業 - 豊島区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは公式情報をもとにした概要です。対象要件・助成額・申請方法は変更される場合があり、ご自身が対象になるかどうかは、必ず豊島区の公式ページや高齢者総合相談センターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
