insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-toshima-hearing-aid","status":"published","title":"豊島区 高齢者補聴器購入費助成事業","officialUrl":"https://www.city.toshima.lg.jp/379/koureisyazigyo/1805080937.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-toshima-hearing-aid:dG9reW8tdG9zaGltYS1oZWFyaW5nLWFpZHzosYrl' from public.support_programs sp where sp.slug='tokyo-toshima-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-hearing-aid', '高齢者補聴器購入費用助成（東京都北区）', '東京都北区が実施する、65歳以上の中等度難聴の高齢者を対象とした補聴器購入費の助成制度。住民税の課税状況などの要件を満たし、聴覚障害の身体障害者手帳を持たない方が対象となる可能性があります。助成上限は7万円とされていますが、対象・金額・所得要件は変更されることがあるため、公式ページや高齢福祉課でご確認ください。', '東京都北区では、65歳以上で中等度の難聴がある方が補聴器を買うときの費用の一部（上限7万円とされています）を区が助成する制度があります。住民税が非課税であることなどの条件があり、聴覚障害の身体障害者手帳をお持ちでない方が対象です。補聴器を買う前に、まず北区の高齢福祉課に相談することが必要とされています。条件や金額は変わることがあるので、必ず公式の案内や窓口でご確認ください。', 'subsidy', '北区内に住民登録がある満65歳以上で、住民税非課税または均等割のみ課税の方・生活保護受給者等、かつ聴覚障害の身体障害者手帳を持たず、耳鼻咽喉科医により中等度難聴（4分法で両耳とも聴力レベル40dB以上70dB未満）と判定された方が対象となる可能性があります。過去にこの助成を受けていないこと等の条件もあるとされています。詳しい要件は公式で確認してください。', '助成上限額は7万円（購入額が上限に満たない場合は購入額。1,000円未満切捨て）とされています。金額は変更される場合があるため公式でご確認ください。', '耳鼻咽喉科の受診から3か月以内に申請書を提出し、交付決定日から6か月以内に補聴器を購入する必要があるとされています。年度や予算により取り扱いが変わる場合があるため公式でご確認ください。', '補聴器を購入する前に、まず北区高齢福祉課（高齢相談係）の窓口で相談・申請書の受け取りを行います。耳鼻咽喉科を受診して医師の意見を記入してもらい、受診から3か月以内に申請書を窓口へ提出します。交付決定通知を受け取った後、決定日から6か月以内に補聴器を購入し、領収書等を持って高齢福祉課に助成金を請求する流れとされています。詳細・最新の手続きは公式ページや窓口でご確認ください。', '申請書（医師の意見記載欄を含む）、本人確認書類、補聴器購入の領収書（原本）、保証書、管理医療機器認証番号が記載された説明書などが必要とされています。必要書類は変更される場合があるため公式でご確認ください。', FALSE, '北区役所 福祉部 高齢福祉課 高齢相談係', '03-3908-9083', NULL, 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008625.html', '高齢者補聴器購入費用助成｜東京都北区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は公式ページをもとにした概要です。対象・金額・所得要件・聴力基準・申請期限などは変更される場合があるため、必ず北区公式ページまたは高齢福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
