insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-kita-hearing-aid","status":"published","title":"高齢者補聴器購入費用助成（東京都北区）","officialUrl":"https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008625.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-kita-hearing-aid:dG9reW8ta2l0YS1oZWFyaW5nLWFpZHzpq5jpvaLo' from public.support_programs sp where sp.slug='tokyo-kita-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-hearing-aid', '荒川区高齢者補聴器購入費助成事業', '荒川区が、加齢などにより聞こえにくくなった高齢者を対象に、医療機器である補聴器の購入費の一部を助成する区独自の制度です。区内在住の満65歳以上で、耳鼻咽喉科の医師が補聴器の必要性を認め、障害者総合支援法に基づく補装具費の支給を受けられない方が対象です(聴力はおおむね中等度難聴程度)。助成金の上限額は72,450円で、1人につき5年間に1台までとされています。助成を受けるには事前に区へ相談し、助成決定の通知を受けてから補聴器を購入する流れです。詳細・最新の条件は荒川区の公式ページでご確認ください。', '耳が聞こえにくくなった65歳以上の方が補聴器を買うとき、荒川区が費用の一部(上限72,450円・5年に1台まで)を助成してくれる制度です。先に区へ相談して、許可の通知をもらってから補聴器を買うのがポイントです。まずは公式ページや区の窓口で、ご自身が対象になるか確認してみましょう。', 'subsidy', '荒川区内に住所のある満65歳以上で、耳鼻咽喉科の医師が補聴器の必要性を認め、障害者総合支援法第76条第1項の補装具費の支給を受けられない方が対象です。聴力はおおむね中等度難聴(聞き間違いを感じる)程度とされています。詳しい聴力基準などは公式ページでご確認ください。', '助成金の上限額は72,450円で、1人につき5年間に1台までです(公式ページに記載)。実際の助成額や最新の条件は荒川区の公式ページでご確認ください。', '申請した年度内(3月末日まで)に補聴器を購入し、助成金を請求する必要があります。詳細は公式ページでご確認ください。', 'まず荒川区(高齢者福祉課)へ相談し(代理での相談も可)、申請書を受け取ります。申請書を持って耳鼻咽喉科を受診し、医師の意見欄を記入してもらったうえで、区の窓口へ申請書を提出します。区の審査・助成決定通知を受けてから補聴器を購入し、領収書等を添えて助成金を請求すると、後日指定口座へ振り込まれます。詳細・最新の手続きは公式ページでご確認ください。', '医師意見欄を記入済みの申請書、補聴器の領収書(写し)、保証書(写し)または購入品がわかる書類など。必要書類の詳細は公式ページ・窓口でご確認ください。', FALSE, '荒川区 福祉部 高齢者福祉課 高齢者福祉係', '03-3802-3111', 'https://www.city.arakawa.tokyo.jp/a028/koureisya-sabisu/hotyouki.html', 'https://www.city.arakawa.tokyo.jp/a028/koureisya-sabisu/hotyouki.html', '荒川区高齢者補聴器購入費助成事業／荒川区公式サイト', '2026-06-24', 'high', ARRAY['targetPeople']::text[], '本情報は荒川区公式サイト(最終更新2025年5月23日・令和7年度版)を確認日時点で参照し概括したものです。助成額・対象要件・聴力基準・申請手続きは変更される場合があり、必ず公式ページまたは区の窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
