insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-arakawa-hearing-aid","status":"published","title":"荒川区高齢者補聴器購入費助成事業","officialUrl":"https://www.city.arakawa.tokyo.jp/a028/koureisya-sabisu/hotyouki.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-arakawa-hearing-aid:dG9reW8tYXJha2F3YS1oZWFyaW5nLWFpZHzojZLl' from public.support_programs sp where sp.slug='tokyo-arakawa-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-hearing-aid', '高齢者補聴器購入費助成（板橋区）', '板橋区が、聴覚障害で身体障害者手帳の交付対象とならない高齢者を対象に、補聴器の購入費の一部を助成する区独自の制度です。区内在住の65歳以上で、耳鼻咽喉科医が中等度以上の難聴と判定し、住民税非課税世帯に該当する方が対象となる可能性があります。上限額や要件は区が定めており、購入前に交付決定を受ける必要があります。詳細・最新の内容は必ず板橋区の公式ページでご確認ください。', '耳の聞こえにくさで身体障害者手帳が出ない高齢の方に、板橋区が補聴器を買うお金の一部を助けてくれる制度です。区内に住む65歳以上で、耳鼻科の先生が補聴器が必要と判断し、住民税がかからない世帯の方が対象になる場合があります。補聴器を買う前に区の手続き（交付決定）が必要です。くわしくは区の公式ページや窓口でご確認ください。', 'subsidy', '板橋区内に住所を有する65歳以上で、聴覚障害により身体障害者手帳の交付対象とならず、耳鼻咽喉科医が中等度以上の難聴と判定し、補聴器の使用が望ましいと認めた方。住民税非課税世帯であることなどが要件とされており、対象となる可能性があります。詳細な要件・所得基準は板橋区の公式ページでご確認ください。', '補聴器の購入費のうち、上限5万円を助成（助成は一人1回限り）。修理費・付属品のみの購入は対象外とされています。金額・条件は変更される場合があるため、最新情報は公式ページでご確認ください。', '聴力検査の検査日から3か月以内に申請する必要があるとされています。最新の取扱いは公式ページでご確認ください。', '高齢政策課（区役所）またはおとしより相談センター（区内19か所）等で申請書を入手し、耳鼻咽喉科を受診のうえ、医師の意見・聴力検査結果を添えて申請窓口に提出します。区の審査・交付決定を受けてから補聴器を購入する流れです（補聴器購入前の交付決定が必要）。手続きの詳細・必要書類は公式ページでご確認ください。', '申請書（医師の意見欄記載あり）、聴力検査結果（検査日から3か月以内）など。転入された方は住民税非課税であることを示す書類が必要となる場合があります。必要書類は公式ページでご確認ください。', FALSE, '板橋区 健康生きがい部 高齢政策課 高齢者相談・給付係', '03-3579-2464', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1031785.html', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1031785.html', '高齢者補聴器購入費助成｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は板橋区公式ページ（2024年4月1日制度改正の案内を含む）をもとに作成した概要です。助成額・対象・所得要件・申請手続きは変更される場合があり、申請により必ず助成を受けられることを保証するものではありません。最新かつ正確な内容は必ず板橋区の公式ページ・窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
