insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-itabashi-hearing-aid","status":"published","title":"高齢者補聴器購入費助成（板橋区）","officialUrl":"https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1031785.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-itabashi-hearing-aid:dG9reW8taXRhYmFzaGktaGVhcmluZy1haWR86auY' from public.support_programs sp where sp.slug='tokyo-itabashi-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-hearing-aid', '練馬区 高齢者聞こえのコミュニケーション支援事業（補聴器購入費用助成）', '練馬区が実施する、加齢などにより聞こえに不自由のある高齢者の補聴器購入費用を助成する区独自の制度です。区内在住の65歳以上で、身体障害者手帳（聴覚障害）をお持ちでなく、耳鼻咽喉科医師により補聴器の必要性を認められた方などが対象となる可能性があります。助成の上限額は住民税の課税状況により異なり、購入前の申請が必要とされています。対象要件・金額は変更される場合があるため、最新の内容は練馬区の公式ページでご確認ください。', '練馬区にお住まいの65歳以上の方で、聞こえにくさのために補聴器が必要と耳鼻咽喉科の医師に認められた場合などに、補聴器の購入費の一部を区が助成する制度です。買う前の申請が必要で、お住まいの地域の地域包括支援センターか区の高齢者支援課に相談・申請します。対象や金額は変わることがあるので、公式ページで最新情報を確認してください。', 'subsidy', '練馬区に住所を有する65歳以上で、身体障害者手帳（聴覚障害）をお持ちでなく、耳鼻咽喉科医師により補聴器の必要性を認められ、両耳の聴力レベルが一定範囲（公式では40デシベル以上70デシベル未満とされています）にある方などが対象となる可能性があります。詳しい要件は練馬区の公式ページでご確認ください。', '助成の上限額は、公式ページでは住民税非課税者72,000円、住民税課税者36,000円とされています（1人1台・回数制限あり）。購入額が上限に満たない場合は購入額が助成額となります。金額は変更される場合があるため公式でご確認ください。', '医師意見欄の作成日から一定期間内（公式では3か月以内とされています）の申請が必要とされ、助成決定後の請求にも期限が設けられています。最新の期限は公式ページでご確認ください。', '購入前の申請が必要です。地域包括支援センターまたは練馬区役所高齢者支援課の窓口で申請書を受け取り、医師意見欄の作成後に区へ提出します（郵送による提出も可とされています）。詳細な手順は公式ページでご確認ください。', '申請書、医師意見欄、補聴器購入の領収書原本、請求書兼口座振替依頼書などが必要とされています。最新の必要書類は公式ページでご確認ください。', FALSE, '練馬区 高齢者支援課 在宅介護支援係', '03-5984-4597', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/20210419134246065.html', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/20210419134246065.html', '高齢者聞こえのコミュニケーション支援事業（補聴器購入費用助成）：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象要件・助成額・聴力基準・申請期限などは改正される場合があります。本ページは概要であり、最終的な可否は練馬区の審査によります。必ず公式ページで最新の内容をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
