insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-nerima-hearing-aid","status":"published","title":"練馬区 高齢者聞こえのコミュニケーション支援事業（補聴器購入費用助成）","officialUrl":"https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/20210419134246065.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-nerima-hearing-aid:dG9reW8tbmVyaW1hLWhlYXJpbmctYWlkfOe3tOmm' from public.support_programs sp where sp.slug='tokyo-nerima-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-hearing-aid', '高齢者補聴器購入費用助成事業（足立区）', '足立区が実施する高齢者向けの補聴器購入費用助成です。区内在住で身体障害者手帳（聴覚）の対象とならない中等度難聴の高齢者が、耳鼻咽喉科専門医の意見書を得たうえで申請でき、補聴器本体の購入費の一部（上限あり・1人1台1回限り）が助成されます。詳細・最新の要件は足立区公式でご確認ください。', '足立区にお住まいで65歳以上の方のうち、補聴器が必要な中等度の難聴があり、聴覚の障害者手帳には該当しない方を対象に、補聴器の購入費を区が助成する制度です（上限5万円・1人1台1回限り）。まず耳鼻咽喉科で医師に意見を書いてもらい、区に申請して「助成OK」の通知が届いてから補聴器を買い、あとで領収書を出すとお金が振り込まれます。決定通知の前に買うと対象外になるので注意してください。対象になるかどうかや金額は、必ず足立区の公式案内でご確認ください。', 'subsidy', '足立区内に住所を有する満65歳以上で、両耳の聴力レベルがおおむね40デシベル以上70デシベル未満の中等度難聴であり、聴覚障害による身体障害者手帳をお持ちでなく、耳鼻咽喉科専門医の診断（意見書）を得られる方が対象です。具体的な聴力基準・対象要件は公式でご確認ください。', '助成上限額は50,000円で、1人につき1台・1回限りです。故障・修理・メンテナンスは対象外で、耳鼻咽喉科の受診・検査費用、証明書料、送料等は自己負担となります。最新の上限額・対象外項目は足立区公式でご確認ください。', '申請期限・受付期間は足立区公式でご確認ください。', '申請書を足立区ホームページ・高齢福祉課などで入手し、耳鼻咽喉科を受診して医師の意見欄を記入してもらったうえで窓口に提出します。区の決定通知を受けてから補聴器を購入し、領収書等を添えて助成申請（償還払い）を行うと本人口座に助成金が振り込まれる流れです。決定通知前に購入したものは助成対象外となるため、手順と必要書類は公式でご確認ください。', '申請書（医師の意見欄に耳鼻咽喉科専門医の証明が必要）、補聴器購入後の領収書、交付申請書・請求書など。詳細・最新の必要書類は足立区公式でご確認ください。', FALSE, '足立区 高齢福祉課（高齢者地域包括ケア推進課 在宅支援係）', '03-3880-5257', 'https://www.city.adachi.tokyo.jp/', 'https://www.adachi-faq.jp/faq.asp?faqno=FQA06534&sugtype=0&did0=113&dname0=%E5%81%A5%E5%BA%B7%E3%83%BB%E7%A6%8F%E7%A5%89', '高齢者補聴器購入費用助成事業を申請したい。（足立区よくある質問）', '2026-06-24', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText', '所得制限の有無', '専用HTML制度ページのURL']::text[], '本内容は足立区の公式情報をもとにした概要です。対象要件・助成額・申請期限・必要書類は変更される場合があり、最終的な可否は区の審査によります。最新かつ正確な情報は足立区公式サイト・担当課でご確認ください。', 'review', NULL, now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
