insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-adachi-hearing-aid","status":"review","title":"高齢者補聴器購入費用助成事業（足立区）","officialUrl":"https://www.adachi-faq.jp/faq.asp?faqno=FQA06534&sugtype=0&did0=113&dname0=%E5%81%A5%E5%BA%B7%E3%83%BB%E7%A6%8F%E7%A5%89","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-adachi-hearing-aid:dG9reW8tYWRhY2hpLWhlYXJpbmctYWlkfOmrmOm9' from public.support_programs sp where sp.slug='tokyo-adachi-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-hearing-aid', '高齢者補聴器購入費助成（葛飾区）', '葛飾区が、耳鼻咽喉科医により補聴器の装用が必要と認められた65歳以上の区民を対象に、補聴器本体の購入費の一部を助成する区独自の制度です。対象や助成額には所得や聴力レベルなどの要件があり、詳細は公式ページや所管課で確認してください。', '耳が聞こえにくくなった65歳以上の葛飾区民で、お医者さん（耳鼻咽喉科）に補聴器が必要と認められた方が、補聴器を買うときの費用の一部を区から助成してもらえる可能性がある制度です。所得などによって助成される金額が変わります。買う前に申請して助成決定を受ける必要がある点に注意してください。', 'subsidy', '葛飾区在住で満65歳以上の方のうち、聴覚障害で身体障害者手帳の交付対象とならず、耳鼻咽喉科医により補聴器の装用が必要と認められた方が対象となる可能性があります。両耳の聴力レベルや過去の助成歴などの要件があり、対象に該当するかは公式ページや所管課でご確認ください。', '補聴器本体の購入費を助成。公式情報では住民税非課税の方は144,900円まで、住民税課税の方は72,450円まで（購入額が上限未満の場合は購入額全額）とされていますが、金額・上限は変更される場合があるため、必ず葛飾区公式ページで最新の内容をご確認ください。', '受診後一定期間内（公式情報では受診後6か月以内）の申請が必要とされ、助成決定前に購入した補聴器は対象外とされています。受付状況・期限は変更される場合があるため公式ページでご確認ください。', '葛飾区役所2階の高齢者支援課窓口、高齢者総合相談センター、区内の耳鼻咽喉科医院・補聴器販売店などで申請でき、郵送による申請も可能とされています。申請書は区の公式ホームページからダウンロードできます。補聴器の購入前に申請し、助成決定を受ける必要がある点にご注意ください。詳しい手順は公式ページでご確認ください。', '助成金の申請書（医師の意見欄の記入を含む、または耳の健康診査結果を添付したもの）、補聴器の見積書などが必要とされています。詳細・最新の必要書類は公式ページや所管課でご確認ください。', FALSE, '葛飾区 高齢者支援課 在宅サービス係', '03-5654-8299', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002144/1038848.html', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002144/1038848.html', '高齢者補聴器購入費助成｜葛飾区公式サイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '聴力レベル要件', '所得区分による上限額']::text[], '本ページは葛飾区公式サイトの情報をもとに作成した概要です。対象要件・助成額・申請方法は変更される場合があり、また個別の状況により取り扱いが異なることがあります。申請の可否や受給は審査により決定され、当サイトが受給を確約するものではありません。最新かつ正確な内容は必ず葛飾区の公式ページや所管課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
