insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-katsushika-hearing-aid","status":"published","title":"高齢者補聴器購入費助成（葛飾区）","officialUrl":"https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002144/1038848.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-katsushika-hearing-aid:dG9reW8ta2F0c3VzaGlrYS1oZWFyaW5nLWFpZHzp' from public.support_programs sp where sp.slug='tokyo-katsushika-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-hearing-aid', '高齢者補聴器購入費助成（江戸川区）', '江戸川区が、加齢などにより聞こえにくくなった高齢の区民を対象に、補聴器の購入費用の一部を助成する区独自の制度です。聴覚の身体障害者手帳をお持ちでない方が対象となる可能性があります。助成額や所得などの要件は公式ページでご確認ください。', '耳が聞こえにくくなった高齢の区民が、補聴器を買うときの費用の一部を江戸川区が助けてくれる制度です。手帳がなくても対象になる場合があります。買う前に申請が必要です。', 'subsidy', '満65歳以上の江戸川区民で、聴覚による身体障害者手帳をお持ちでなく、医師から補聴器が必要と認められた方などが対象となる可能性があります。住民税の課税状況など所得に関する要件が設けられている場合があります。詳しい対象条件は公式ページで確認してください。', '助成額には上限が設けられている可能性があります（公式案内では住民税非課税の方は上限4万円、課税の方は上限2万円との記載があります）。最新の金額・所得区分は公式ページで確認してください。', '通年で受け付けている可能性がありますが、予算や年度の状況により異なる場合があります。公式ページで確認してください。', '原則として購入前の事前申請が必要です。申請書に聴力検査結果（オージオグラム）などを添えて、区の担当課窓口・郵送・電子申請（ぴったりサービス）で手続きする方法が案内されています。区の助成決定前に購入した補聴器は対象外となる場合があるため、申請の順序を公式ページで確認してください。', '申請書、聴力検査の結果（オージオグラム／純音聴力検査表、3か月以内のもの）、本人確認書類などが必要となる場合があります。必要書類は公式ページで確認してください。', TRUE, '江戸川区 福祉部 福祉推進課 孝行係', '03-3652-1151', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/hochoki.html', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/hochoki.html', '高齢者補聴器購入費助成 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone']::text[], '本ページは江戸川区の公式情報をもとにした概要です。助成額・対象・所得要件・申請方法は変更される場合があり、対象となるかどうかは区の審査によって判断されます。最新かつ正確な内容は必ず江戸川区の公式ページや担当課でご確認ください。江戸川区には別途、18歳未満を対象とした『中等度難聴児補聴器購入費助成』もあります。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
