insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"tokyo-edogawa-hearing-aid","status":"published","title":"高齢者補聴器購入費助成（江戸川区）","officialUrl":"https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/hochoki.html","topic":"hearing-aid"}'::jsonb, 'pilot:tokyo-edogawa-hearing-aid:dG9reW8tZWRvZ2F3YS1oZWFyaW5nLWFpZHzpq5jp' from public.support_programs sp where sp.slug='tokyo-edogawa-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/hochoki-konyuhi.html', 'WebFetchでprimaryのofficialUrl（高齢者補聴器購入費の助成）を検証: (a)到達可——タイトル「高齢者補聴器購入費の助成」。(b)千代田区公式（www.city.chiyoda.lg.jp/.lg.jp、法人番号8000020131016）。(c)千代田区の補聴器購入費助成そのものの専用ページで当該区一致。(d)更新日2026-06-01・現在実施中で古い年度PDF/受付終了でない。(e)国制度の一般説明ではなく区独自制度。(f)対象は『60歳以上・中等度難聴の医師診断・聴覚障害による身障手帳なし・過去未受給』で対象者の一部を全体と書いていない（高齢者向けとして正しく限定）。(h)金額（課税72,450円/非課税144,900円）・申請期限（交付決定日から6か月以内に請求）・必要書類・窓口（在宅支援課03-6265-6482/6486）はすべて原文と一致し非断定。第2URL（60歳未満・障害者福祉課03-5211-4214・18歳以上9割/18歳未満全額・上限50,000円・一耳40dB以上）も別途実在・実施中を確認。唯一の指摘は criterion (g): ' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/sonota/hotyoki.html', '敵対的検証: program.officialUrl(https://www.city.chuo.lg.jp/a0028/.../hotyoki.html)をWebFetchで再取得し、一次調査の主張を逐一照合した。(a)到達=200・本文取得可。(b)公式=中央区ドメインcity.chuo.lg.jp(.lg.jp)で確定。(c)補聴器購入費用助成「そのもの」のページであり当該区(中央区)。(d)受付終了でなく現在実施中、令和7年8月1日改定の新しい内容。(e)国制度ではなく中央区独自の高齢者向け制度。(f)対象者の一部を全体と誤記していない=「65歳以上の区内在住者」「耳鼻咽喉科医が必要と認める」「過去5年間未受給」「聴覚障害の身体障害者手帳所持者は除く」を公式で確認、一次調査の記載と一致。(g)複数制度の混同なし=researchNoteが中等度難聴児発達支援事業・補装具費給付の別制度の存在に言及しつつ、本programは高齢者向け制度のみで構成。(h)断定回避=金額(非課税72,000円/課税35,000円)・申請方法・必要書類・期限は「とされています」「可能性がある」「公式で' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/zaitakushien/koureisya/hoctyouki/hotyoukijyosei.html', '敵対的検証として program.officialUrl を WebFetch で2回精読。(a)到達OK。(b)港区公式ドメイン www.city.minato.tokyo.jp 上のページで .tokyo.jp 要件を満たす。(c)「高齢者補聴器購入費助成事業」という補聴器購入費助成「そのもの」のページで当該区(港区)の制度。(d)ページ更新日2026-03-13・受付終了/過去年度PDFの記載なし=現行制度。(e)国制度の一般説明ではなく港区独自の高齢者向け制度(対象=60歳以上又は区の高齢者聴力検査対象者で、聴覚障害の身体障害者手帳未取得・補聴器相談医が装用必要と認める者)。(f)対象者を一部=全体と誤記しておらず、program.targetPeople は「〜可能性があります/公式で確認」と概括し非断定。(g)複数制度の混在なし(単一制度)。(h)FORBIDDEN/断定なし。金額・所得・対象は概括し「公式で確認」を付す。金額について検証: 一次調査メモの懸念通り、現行公式ページ本文では非課税者=補聴器購入額(上限144,900円)/課税者=1/2(上限72,450円)と明' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00009.html', '敵対的検証を実施。program.officialUrl（https://www.city.shinjuku.lg.jp/fukushi/file05_02_00009.html）をWebFetchで再取得し、8項目を点検した。(a)到達=200で到達。(b)公式=www.city.shinjuku.lg.jpは新宿区公式の.lg.jpドメイン。(c)補聴器助成そのもののページで当該区=ページタイトル「補聴器の支給等」で新宿区の65歳以上向け補聴器の現物支給・購入費助成を直接扱う。(d)古い年度/受付終了でない=「令和8年4月1日より、制度内容が変わりました」と明記され経過措置の案内もある最新版。受付終了の記載なし、確認日（2026-06-24）時点で現在実施中。(e)国制度の誤認なし=新宿区独自の高齢者向け制度であり国制度の一般説明ではない。(f)対象者の一部を全体と書いていない=「65歳以上で聴力が低下した方（障害者制度で支給されていない方）」というスコープを過大化せず記載。(g)複数制度の混同なし=同一公式ページ上の現物支給と購入費助成は単一の区独自制度の2つの給付方法であり許容' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinjuku' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.bunkyo.lg.jp/b017/p003186.html', '敵対的検証を実施。program.officialUrl（https://www.city.bunkyo.lg.jp/b017/p003186.html ）をWebFetchで再取得し、(a)到達可、(b)文京区公式ドメイン（city.bunkyo.lg.jp＝.lg.jp）、(c)「高齢者補聴器購入費用助成事業」という補聴器購入費助成そのもののページで当該区（文京区）、(d)令和7年4月1日から助成上限額・対象者が変更され現在実施中＝古い年度PDF/受付終了ではない、(e)国制度の一般説明ではなく区独自制度、(f)対象者の一部を全体と誤記していない、(g)複数制度を1件に混在させていない、(h)FORBIDDEN/断定なし・区差のある金額/所得/対象は概括＋「公式で確認」、をすべて確認した。一次調査の主要事実（区内在住65歳以上〔申請年度に65歳になる64歳含む〕、聴覚障害の障害者手帳非保有者〔ただし手帳保持者でも納税額制限で補装具費を受けられない場合は対象〕、医師の必要性診断、過去5年以内に助成決定なし、上限72,450円〔片耳/両耳問わず本体購入費〕、耳鼻咽喉科で申請書兼意見書→' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='bunkyo' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/kikoe.html', '公式URL(www.city.taito.lg.jp＝台東区公式.lg.jp)をWebFetchで再検証。到達可・補聴器(聞こえの改善機器)購入費助成「そのもの」のページで当該区=台東区。ページ更新日2026年4月1日・受付終了/年度切れの記載なし=現行制度。本文は「台東区独自の高齢者向け助成制度。身体障害者手帳所有者向けの国制度とは別」と明記しており、国制度の一般説明の誤認や障害者向け別制度との混在はない。対象=65歳以上で耳鼻咽喉科医が補聴器装用必要と認め、聴覚障害の身体障害者手帳を持たず、過去に本助成未受給の区民——一部を全体と書く誤りなし。助成上限(住民税非課税・生活保護144,900円/課税72,450円)、医師意見書は記入日から3か月以内、請求は申請日の翌年度末、窓口=区役所2階5番高齢福祉課、問い合わせ=高齢福祉課 総合相談・給付担当 03-5246-1227——いずれも公式記載と一致。金額・所得区分・期限・必要書類は区差・変更可のため概括+「公式で確認」で記述しuncertainFieldsに計上済み。FORBIDDEN表現や断定なし。是正不要、全項目適合のためok=t' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='taito' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/ziritu_sien/ta90200020150714170.html', '敵対的検証を実施。officialUrl(kenko_fukushi/koureisya_kaigohoken/ziritu_sien/ta90200020150714170.html)をWebFetchで確認: (a)到達OK (b)墨田区公式ドメインcity.sumida.lg.jp(.lg.jp) (c)「高齢者の補聴器購入費を助成しています」という補聴器購入費助成そのものの当該区ページ (d)更新日2026-04-01・令和8年4月1日から助成上限額拡充の現行制度で受付終了/古い年度ではない (e)国制度の一般説明ではなく区独自事業 (f)対象者の一部を全体と誤記していない (g)別所管の「中等度難聴児の補聴器購入費助成」(障害者福祉課)はresearchNoteで言及のみ・本program(高齢者向け)に混在させていない (h)区差のある金額/所得/聴力基準は概括+「公式で確認」表現でFORBIDDEN断定なし。公式記載と一致を確認した点: 対象=区内在住満65歳以上/聴覚障害の身体障害者手帳交付対象外/5年以内に本助成未受給/両耳4分法で中等度難聴(40dB以上70dB未満' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='sumida' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6597.html', '敵対的検証完了。program.officialUrl (https://www.city.koto.lg.jp/212106/fukushi/koresha/service/jisshi/6597.html) をWebFetchで再到達確認。(a)到達OK (b)江東区公式ドメイン city.koto.lg.jp（.lg.jp）でありニセサイト・第三者サイトでない (c)「高齢者補聴器の現物支給及び購入費助成」という補聴器助成そのものの当該区(江東区)ページ (d)更新日2026-06-16・受付終了や古い年度PDFでなく実施中 (e)国制度の一般説明ではなく区独自の高齢者向け制度として正しく記載 (f)対象は「江東区在住65歳以上で障害者総合支援法による補聴器支給を受けていない方」と全体ではなく要件付きで正しく記述、再支給は前回から5年経過 (g)障害児向け「中等度難聴児補聴器購入費支給」とは別制度として高齢者制度のみで1件に統一・混在なし (h)金額(上限72,450円、未満なら実費)は本文一致、所得制限の記載は本文上も無く一次調査の「所得制限の記載なし」と整合、断定的・FORB' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='koto' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/20230428084925.html', 'officialUrlをWebFetchで2回検証。当該ページは品川区公式ドメインの『高齢者補聴器購入費助成事業』(65歳以上)のページで現行(更新日2026-04-01・受付終了なし)。一次調査が同ページに無い18-64歳向け『中等度難聴者補聴器購入助成事業』(障害者支援課03-5742-6710/所得負担上限)を1recordに混在させていたため、officialUrlが実証する高齢者向け単体にスコープ是正し別制度は非断定で言及に留めた。是正後は公式一致・単一制度・非断定をすべて満たす。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinagawa' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/hochouki.html', '公式URL(city.meguro.tokyo.jp)をWebFetchで再到達・確認。専用ページで制度名=高齢者補聴器購入費助成事業、更新日2026-04-01・現行。対象=満65歳以上・住民税非課税・補装具対象外・耳鼻咽喉科専門医証明（両耳40～70dB未満等）。改定前金額50,000円は公式に記載なく検証不能のため是正し、公式に確認できる上限70,000円表現へ統一。単一制度・断定回避・公式一致。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='meguro' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/hocyouki.html', '敵対的検証完了。一次調査のofficialUrl(https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/hocyouki.html)をWebFetchで再取得し、全チェック項目に適合することを確認。(a)到達OK (b)大田区公式 www.city.ota.tokyo.jp(.tokyo.jp) (c)制度名「高齢者補聴器購入費助成」そのもののページで当該区=大田区 (d)更新日2026-04-01・令和8年4月1日改正で現在有効、受付終了/古い年度PDFでない (e)区独自制度であり国制度の誤認なし (f)対象者(満65歳以上・聴覚障害の身体障害者手帳なし・耳鼻咽喉科医が必要と認める・過去5年以内に未受給)を全体として正しく記述 (g)単一制度のみ (h)FORBIDDEN/断定なし、金額(一人1回5万円上限・5年に1回)は公式表現と一致し概括+公式確認を促す形。重要な確認点として、当ページは令和8年4月1日改正で『住民税課税世帯を助成対象に拡充』と明記=従来あった所得(非課税)要件が緩和された。一次調査はtarget' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='ota' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.setagaya.lg.jp/02082/10803.html', 'officialUrlをWebFetchで検証し、.lg.jp公式の世田谷区補聴器購入費助成ページ(65歳以上向け)であること、現行制度で受付終了記載がないことを確認。二次URL(18歳から64歳向け)も併せて確認し金額を裏取り。チェック項目(a)〜(h)全て充足、ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='setagaya' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/hocyouki-jyosei.html', '敵対的検証を実施。program.officialUrl(city.shibuya.tokyo.jp の公式ポータル「高齢者補聴器購入費助成」ページ)をWebFetchで取得し、以下を確認した。(a)到達=200・正常表示。(b)公式ドメイン=city.shibuya.tokyo.jp(.tokyo.jp)で渋谷区公式。(c)補聴器購入費助成「そのもの」のページであり当該区(渋谷区)。(d)更新日2026-06-23・受付終了/停止の記載なし=現行制度。(e)国制度の一般説明ではなく渋谷区独自の高齢者向け制度。(f)対象者は本文どおり「65歳以上・区内在住・住民税非課税または合計所得135万円以下・耳鼻咽喉科専門医の証明・聴覚障害による身体障害者手帳の対象外」を満たす者で、一部を全体と書いていない。(g)複数制度の混在なし=単一制度。(h)断定的なFORBIDDEN表現なし、金額・所得・対象は概括+「公式で確認」を付している。\n\n争点だった金額について追加検証: 公式本文(WebFetch)では助成上限72,000円と案内され、申請時期による違いの記載は本文上は見当たらなかったが、' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shibuya' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/0235245120240605163422503.html', '公式URL（www.city.tokyo-nakano.lg.jp＝中野区公式.lg.jpドメイン）をWebFetchで再取得し、一次調査の主張を全項目照合した。検証チェックリスト全適合：(a)到達OK (b)公式.lg.jpドメイン (c)タイトル「高齢者の方へ、補聴器購入費用を助成します（注意：購入済の補聴器は対象外です）」で中野区独自の補聴器購入費助成「そのもの」のページ・当該区一致 (d)最終更新2025-12-09・受付終了記載なし＝現在実施中 (e)国制度の一般説明ではなく中野区高齢者向け独自制度 (f)対象者（65歳以上・世帯全員前年合計所得350万円未満・中等度難聴40〜70dBまたは医師が装用必要と認定・過去5年以内未受給）を一部=全体と書いていない (g)中等度難聴児向け助成と混在させず高齢者向け単一制度に限定 (h)FORBIDDEN語・断定なし、区差のある金額/所得/対象は概括＋「公式で確認」で統一。公式記載と数値も一致＝助成上限片耳45,000円/両耳90,000円、所得350万円未満、難聴40〜70dB、申請は郵送・窓口（区役所・地域包括支援センター）・電子' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nakano' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.suginami.tokyo.jp/s039/1170.html', '敵対的検証を実施。program.officialUrl（https://www.city.suginami.tokyo.jp/s039/1170.html）をWebFetchで再取得し、以下を確認した。(a)到達可、(b)杉並区公式ドメイン（city.suginami.tokyo.jp）、(c)「高齢者補聴器購入費助成」制度そのもののページで当該区（杉並区）に合致、(d)更新日2026-04-02・受付終了/廃止/古い年度の記載なし・現在実施中、(e)国制度ではなく区独自制度（認知症予防・コミュニケーション支援を目的）、(f)対象者は「満65歳以上・身体障害者手帳交付対象外・補聴器相談医が必要性を認めた者」と正しく限定され全体化していない、(g)中等度難聴児向け別制度（/s036/8079.html）と混同せず高齢者向け1件に絞られている、(h)FORBIDDEN/断定なし。是正点1つのみ: 一次調査は金額をuncertainFields計上し本文で概括していたが、ライブ公式ページが助成限度額を明記（非課税世帯72,450円／課税世帯36,230円）していることを確認したため、ben' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='suginami' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.toshima.lg.jp/379/koureisyazigyo/1805080937.html', '敵対的検証: program.officialUrl(https://www.city.toshima.lg.jp/379/koureisyazigyo/1805080937.html)をWebFetchで再取得し全項目を点検。(a)到達OK (b)豊島区公式ドメインcity.toshima.lg.jp (c)「高齢者補聴器購入費助成事業｜豊島区公式ホームページ」=補聴器購入費助成そのもののページで当該区 (d)ページ更新日2026-06-17・令和8年4月1日からの再申請要件を記載=受付終了/古い年度ではなく現在実施中 (e)国制度ではなく区独自制度 (f)対象者(満65歳以上+中程度難聴の医師証明+補装具費支給を受けていない)を正しく全体として記載 (g)障害者向け補装具支給(別制度)と混同せず単一制度 (h)FORBIDDEN/断定なし・所得段階による金額差は概括+公式確認を付記。所得段階1〜5=上限50,000円/6以上=上限20,000円も公式と一致。1点是正: 申請期限について一次調査は「明確な記載なし」としていたが、公式に「予算上限に達し次第、当年度分の受付を終了します」' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='toshima' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008625.html', '敵対的検証を実施。program.officialUrl（https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008625.html）をWebFetchで再取得し、以下を確認した。(a)到達可——ページは正常に取得できた。(b)公式——city.kita.lg.jp は北区の公式ドメイン（.lg.jp）。(c)該当性——「高齢者補聴器購入費用助成」そのものの案内ページで、当該区（北区）の制度。(d)現行——更新日2026年4月2日、受付終了・年度切れの記載なし、現在実施中。(e)区独自——国制度の一般説明ではなく北区が実施する高齢者向け助成事業。(f)対象——対象者を一部（満65歳以上・住民税非課税または均等割のみ課税・生活保護受給者・聴覚障害の身体障害者手帳なし・4分法で両耳40dB以上70dB未満）として正しく限定し、全体と誤記していない。(g)単一制度——障害者向け補装具費助成（別ドメイン）と混在させず、高齢者向け1件として整理。(h)断定回避——金額・所得・聴力基準・期限は概括し「公式で確認」を付している' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='kita' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.arakawa.tokyo.jp/a028/koureisya-sabisu/hotyouki.html', '敵対的検証として program.officialUrl をWebFetchで再取得し、(a)到達・(b)荒川区公式(.tokyo.jp = www.city.arakawa.tokyo.jp)・(c)「荒川区高齢者補聴器購入費助成事業」そのもののページで当該区・(d)更新日2025年5月23日/令和7年度版で受付終了や廃止記載なし=現行・(e)障害者総合支援法の補装具費支給対象外を要件とする区独自制度で国制度の誤認なし・(f)対象は「区内在住満65歳以上・耳鼻咽喉科医が必要と認める・補装具費支給対象外」と適切にスコープ・(g)障害児向け「中等度難聴児補聴器購入費助成」を混在させず高齢者向け単一制度・(h)断定/FORBIDDEN表現なし、を確認。一次調査では助成額をuncertainとし「25,000円との表記揺れ」を懸念していたが、公式本文は『助成金の上限額は72,450円』『1人あたり5年間に1台限り』と明確に記載しているため、benefitAmountTextを公式数値で具体化し、uncertainFieldsからbenefitAmountTextを除外した(別サイトの25,0' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='arakawa' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1031785.html', '敵対的検証完了。program.officialUrl（https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1031785.html）をWebFetchで再取得し全項目を照合した。(a)到達=200・有効、404やエラーでない。(b)板橋区公式ドメイン city.itabashi.tokyo.jp に該当。(c)補聴器購入費助成「そのもの」のページで当該区(板橋区)向け＝制度名「高齢者補聴器購入費助成」を確認。(d)古い年度PDF/受付終了でない＝令和8年4月10日更新・令和6年4月1日改正・受付終了の記載なしで現行実施中。(e)国制度の一般説明を区独自と誤認していない＝65歳以上・区内在住・身障手帳交付対象外・住民税非課税世帯・上限5万円・一人1回限りは板橋区独自要件として明記。(f)対象者の一部を全体と書いていない＝targetPeopleは65歳以上/手帳非該当/中等度以上難聴/非課税世帯と限定し「対象となる可能性があります」「公式で確認」と概括・非断定で記載、過大表現なし。(g)複数制度を1件に混ぜていない＝高齢者向け制度' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='itabashi' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/nichijo/20210419134246065.html', '敵対的検証を実施。program.officialUrl をWebFetchで取得し、一次調査の主要事実が公式と一致することを確認した。(a)到達=200で到達。(b)公式=city.nerima.tokyo.jp（練馬区公式ドメイン）。(c)補聴器購入費助成そのもののページで当該区=ページ名「高齢者聞こえのコミュニケーション支援事業（補聴器購入費用助成）」、本文「65歳以上で中等度難聴の方を対象に、補聴器購入費用の一部を助成します」。(d)受付終了でない=終了・受付終了の記載なし、更新日2024年9月18日。(e)国制度の誤認なし=練馬区独自の高齢者向け区事業。(f)対象者の過大表記なし=「対象となる可能性があります」と非断定。(g)複数制度の混在なし=単一制度。なおWebSearchで旧制度ページ「高齢者の補聴器購入費用助成事業（令和6年6月30日申請まで）」(20240820144253552.html)が別途存在することを確認したが、一次調査は現行ページ(20210419134246065.html)を正しく選択している。(h)FORBIDDEN/断定なし=金額（非課税72,0' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nerima' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.adachi-faq.jp/faq.asp?faqno=FQA06534&sugtype=0&did0=113&dname0=%E5%81%A5%E5%BA%B7%E3%83%BB%E7%A6%8F%E7%A5%89', '敵対的検証として program.officialUrl（足立区公式FAQ adachi-faq.jp / FQA06534）を WebFetch で再取得。(a)到達=正常表示・エラーや「該当なし」なし、(b)公式性=adachi-faq.jp は足立区公式のよくある質問システム（city.adachi.tokyo.jp と連動）、(c)当該区・補聴器助成そのもの=「足立区 高齢者補聴器購入費用助成事業」の専用FAQで一致、(d)古い年度/受付終了でない=受付終了・旧年度の記載なし、(e)国制度の誤認なし=区独自事業、(f)対象者の過大記述なし=満65歳以上・区内在住・耳鼻咽喉科専門医の意見書・聴力おおむね40〜70dB（両耳）・身体障害者手帳（聴覚）非該当という公式要件と一致、(g)複数制度の混在なし=高齢者向け単一制度（障害児向け中等度難聴児支援は正しく除外済み）、(h)FORBIDDEN/断定なし・金額/対象は概括+「公式で確認」。FAQ本文で初稿が概括していた数値が確認できた: 助成上限額50,000円・1台1回限り、聴力おおむね40〜70dB（両耳）、身体障害者手帳（聴覚）' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002144/1038848.html', '敵対検証完了（2026-06-24）。program.officialUrl をWebFetchで取得し、葛飾区公式サイト(www.city.katsushika.lg.jp / .lg.jp)の現行「高齢者補聴器購入費助成」ページであることを確認。検証項目すべて適合: (a)到達OK (b)公式.lg.jp (c)補聴器購入費助成そのもののページで当該葛飾区 (d)事業終了/受付終了表示なし・令和7年7月より対象拡大&上限引上げで継続実施中 (e)国制度の誤認なし・区独自事業 (f)対象者の範囲は概括+公式確認誘導で過大記載なし (g)単一制度のみ(旧【事業終了】ページや中等度難聴児ページとは混在させていない) (h)FORBIDDEN/断定なし・金額/所得/対象は概括+「公式で確認」。一次調査データを公式と照合: 助成額(非課税144,900円/課税72,450円・購入額が上限未満なら購入額)、申請期限(受診後6か月以内・助成決定後に購入、決定前購入は対象外)、必要書類(医師意見欄記載の申請書等・見積書)、申請窓口(区役所2階201番高齢者支援課・高齢者総合相談センター・郵送可・H' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/hochoki.html', '公式URL(city.edogawa.tokyo.jp、江戸川区公式)をWebFetchで再取得し検証。(a)到達OK (b)公式ドメイン (c)「高齢者補聴器購入費助成」そのもののページで当該区=江戸川区 (d)更新日2025年10月8日・受付終了/年度切れ記載なし=現行 (e)国制度ではなく区独自の高齢者向け助成 (f)対象者は概括(満65歳以上区民/住民税非課税or区民税所得割額年46万円未満/聴覚の身体障害者手帳なし/耳鼻科医が必要と認定)で一部を全体と誤記なし (g)programは高齢者制度のみで混在なし(中等度難聴児助成はdisclaimerの補足にとどめる=妥当) (h)断定回避・金額/所得/対象は概括+「公式で確認」あり。公式本文と一致確認: 上限額は非課税40,000円/課税20,000円=benefitAmountTextと一致。事前申請必須・窓口/郵送/電子申請(ぴったりサービス)対応=applicationMethodTextと一致。必要書類(申請書/オージオグラム純音聴力検査表3か月以内)=requiredDocumentsTextと整合。担当=福祉部福祉推' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
